defmodule BlogWeb.PostLive do
  use Phoenix.LiveView

  def mount(_params, _session, socket) do
    {:ok, assign(socket, :posts, [])}
  end

  def render(assigns) do
    ~L"""
    <div>
      <%= for post <- @posts do %>
        <div class="post">
          <h2><%= post.title %></h2>
          <div class="content" phx-html="<%= post.content %>">
            <%= raw(post.content) %>
          </div>
        </div>
      <% end %>
    </div>
    """
  end

  def handle_event("add_post", %{"post" => post_params}, socket) do
    posts = [post_params | socket.assigns.posts]
    {:noreply, assign(socket, :posts, posts)}
  end
end